/**
 * Email notification handler — formats and dispatches email notifications
 * for order lifecycle events.
 *
 * Subscribes to order events through the EventBus and records email
 * notifications via the NotificationService, following the same
 * event-driven pattern used throughout the application.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 * - NotificationService for recording notifications
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import type { NotificationService } from '../services/notification.service.js';
import { Logger } from '../utils/logger.js';

/**
 * Human-readable labels for order statuses used in email content.
 */
const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

/**
 * Email subject lines for each status transition target.
 */
const STATUS_EMAIL_SUBJECTS: Record<OrderStatus, string> = {
  pending: 'Order Received',
  confirmed: 'Order Confirmed',
  shipped: 'Your Order Has Shipped',
  delivered: 'Your Order Has Been Delivered',
  cancelled: 'Order Cancelled',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');

  constructor(
    private eventBus: EventBus,
    private notificationService: NotificationService,
  ) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for email notification triggers.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send welcome/confirmation email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemLines = event.order.items
      .map((item) => `  - ${item.name} (x${item.quantity}) — $${(item.quantity * item.unitPrice).toFixed(2)}`)
      .join('\n');

    const body = [
      `Hi ${event.user.name},`,
      '',
      'Thank you for your order! Here is your order summary:',
      '',
      `Order ID: ${event.order.id}`,
      '',
      'Items:',
      itemLines,
      '',
      `Total: $${event.order.total.toFixed(2)}`,
      '',
      'We will notify you when your order status changes.',
    ].join('\n');

    this.notificationService.recordNotification({
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation — ${event.order.id}`,
      body,
    });
  }

  /**
   * Handle order status change — send status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const newStatusLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    const previousStatusLabel = STATUS_LABELS[event.previousStatus as OrderStatus] ?? event.previousStatus;

    this.logger.info(
      `Sending status update email for order ${event.order.id}: ${previousStatusLabel} -> ${newStatusLabel}`,
    );

    const subject = `${STATUS_EMAIL_SUBJECTS[event.newStatus as OrderStatus] ?? 'Order Update'} — ${event.order.id}`;

    const body = [
      `Your order ${event.order.id} has been updated.`,
      '',
      `Previous status: ${previousStatusLabel}`,
      `New status: ${newStatusLabel}`,
      '',
      this.getStatusMessage(event.newStatus as OrderStatus),
    ].join('\n');

    this.notificationService.recordNotification({
      channel: 'email',
      recipient: event.order.userId,
      subject,
      body,
    });
  }

  /**
   * Get a friendly message for the new order status.
   */
  private getStatusMessage(status: OrderStatus): string {
    switch (status) {
      case 'confirmed':
        return 'Your order has been confirmed and is being prepared.';
      case 'shipped':
        return 'Your order is on its way! You will receive a delivery notification soon.';
      case 'delivered':
        return 'Your order has been delivered. Thank you for your purchase!';
      case 'cancelled':
        return 'Your order has been cancelled. If you have any questions, please contact support.';
      default:
        return 'Your order status has been updated.';
    }
  }
}

